const firm = $input.first().json;
const cls = (firm.classification || 'unclear').toLowerCase()
  .replace(/-/g,'').replace(/ /g,'').replace(/_/g,'');

// Path A = Centralized + Hybrid (internal ops team)
// Path B = Decentralized + Network + Hybrid (portfolio cos)
// Path C = Network + Hybrid (external advisors) — deal partners
// Path D = ALL firms (deal team at PE firm)
const pathMap = {
  'centralized':     { A:true,  B:false, C:false, D:true  },
  'hybrid':          { A:true,  B:true,  C:true,  D:true  },
  'networkbased':    { A:false, B:true,  C:true,  D:true  },
  'network':         { A:false, B:true,  C:true,  D:true  },
  'decentralized':   { A:false, B:true,  C:false, D:true  },
  'assetmanagement': { A:false, B:false, C:false, D:false },
  'assetmgmt':       { A:false, B:false, C:false, D:false },
  'unclear':         { A:false, B:true,  C:false, D:true  }
};

const paths = pathMap[cls] || pathMap['unclear'];
const active = Object.entries(paths).filter(([k,v])=>v).map(([k])=>'Path '+k);

return [{ json: { ...firm, run_path_A:paths.A, run_path_B:paths.B, run_path_C:paths.C, run_path_D:paths.D, active_paths:active, classification_normalized:cls }}];

const firm = $('Path Router2').first().json;
const aiResp = $('Prospect Extraction AI2').first().json;
let raw = aiResp.output || aiResp.text || '';
let ai = {};

try {
  const m = raw.match(/\{[\s\S]*\}/);
  if (!m) throw new Error('no JSON');
  ai = JSON.parse(m[0]);
} catch(e) {
  ai = {
    classification_summary: {
      pe_firm_name: firm.pe_firm_name,
      classification: firm.classification,
      operating_team_name: firm.operating_team_name || 'None identified',
      team_size_estimate: 'N/A',
      apac_offices: JSON.stringify(firm.apac_offices_detected || []),
      team_page_url: firm.team_page_url || '',
      portfolio_page_url: firm.portfolio_page_url || '',
      confidence_score: firm.classification_confidence || 0,
      classification_evidence: firm.classification_evidence || '',
      targeting_approach: 'Manual review needed',
      relevant_portfolio_cos_count: 0,
      active_paths: firm.active_paths || []
    },
    prospects: [],
    outreach_sequence: 'Level 1-2 → Level 5 → Level 3-4',
    week1_action: '', week2_action: '', week3_action: ''
  };
}

const cs = ai.classification_summary || {};
const prospects = ai.prospects || [];

// ── Tab 1: Classification Summary row ─────────────────────
const summaryRow = {
  pe_firm_name:              firm.pe_firm_name,
  website_url:               firm.website_url,
  company_linkedin_url:      firm.company_linkedin_url,
  company_country:           firm.company_country,
  industry:                  firm.industry,
  headcount:                 firm.headcount,
  aum_in_billions:           firm.aum_in_billions,
  classification:            firm.classification,
  operating_team_name:       cs.operating_team_name   || firm.operating_team_name || 'None identified',
  team_size_estimate:        cs.team_size_estimate    || 'N/A',
  apac_offices:              cs.apac_offices          || JSON.stringify(firm.apac_offices_detected || []),
  team_page_url:             cs.team_page_url         || firm.team_page_url || '',
  portfolio_page_url:        cs.portfolio_page_url    || firm.portfolio_page_url || '',
  confidence_score:          cs.confidence_score      || firm.classification_confidence || 0,
  classification_evidence:   cs.classification_evidence || firm.classification_evidence || '',
  targeting_approach:        cs.targeting_approach    || '',
  relevant_portfolio_cos:    cs.relevant_portfolio_cos_count || 0,
  active_paths:              JSON.stringify(cs.active_paths || firm.active_paths || []),
  outreach_sequence:         ai.outreach_sequence     || '',
  week1_action:              ai.week1_action          || '',
  week2_action:              ai.week2_action          || '',
  week3_action:              ai.week3_action          || '',
  run_date:                  firm.run_date || new Date().toISOString().split('T')[0],
  green_light:               'PENDING'
};

// ── Tab 2: Prospect rows ───────────────────────────────────
const prospectRows = prospects.map(p => ({
  prospect_name:      p.name             || '',
  title:              p.title            || '',
  company:            p.company          || firm.pe_firm_name,
  pe_backer:          p.pe_backer        || (p.extraction_path === 'Path B' ? firm.pe_firm_name : 'N/A'),
  extraction_path:    p.extraction_path  || '',
  email:              p.email            || '',
  linkedin_url:       p.linkedin_url     || '',
  location:           p.location         || '',
  industry:           p.industry         || '',
  expansion_signals:  p.expansion_signals || '',
  composite_score:    p.composite_score  || 0,
  priority_tier:      p.priority_tier    || 'Priority 3',
  outreach_hook:      p.outreach_hook    || '',
  notes:              p.notes            || '',
  pe_firm_name:       firm.pe_firm_name,
  classification:     firm.classification,
  run_date:           firm.run_date || new Date().toISOString().split('T')[0]
}));

return [{ json: {
  classification: firm.classification,
  summary_row:    summaryRow,
  prospect_rows:  prospectRows,
  prospect_count: prospectRows.length
}}];
